var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"당신이... 벨레스라는 사제야?","JPN":"あなたが……ヴェレスっていう司祭？","ENG":"You're... Father Veles?","TWN":"你……是叫貝雷斯的那位神父嗎？"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"여기까지 오느라 고생 많았습니다, 늑대여.","JPN":"よく来ましたね、オオカミよ。","ENG":"You must have had quite the journey getting here, Wolf.","TWN":"來到這裡真是辛苦你了，狼。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"당신의 행보는 오랫동안 지켜봐 왔지만, 실제로 보는 건 처음이군요.","JPN":"あなたの歩みを長い間見守ってきましたが、実際に会うのは初めてですね。","ENG":"I've been watching your path for a long time, but this is the first time I have seen you in person.","TWN":"你的行動我已觀察很久了，但還是第一次親眼目睹。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"날 지켜봤다고?","JPN":"私を見守っていただって？","ENG":"You've been watching me?","TWN":"你一直在監視我？"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"그렇습니다. 당신이 마왕 타기리온을 쓰러트릴 만큼 강한 운명을 타고났을지 궁금했거든요.","JPN":"そうです。あなたが魔王タギリオンを倒すほどの強い運命に生まれたのか、気になったのです。","ENG":"Yes. I was curious whether you were fated to become strong enough to defeat the Demon Lord Thagirion.","TWN":"沒錯。我很好奇你是否擁有擊敗魔王塔基里翁的強大命運。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"실패를 거듭해온 다른 늑대들과 당신은 다릅니다. 그들의 기억을 모두 계승했으니까요.","JPN":"失敗を繰り返した他のオオカミとあなたは違います。彼らの記憶をすべて継承していますからね。","ENG":"You are different from the other wolves who failed again and again. You inherited all of their memories.","TWN":"你與那些不斷失敗的其他狼不同，你繼承了他們全部的記憶。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"어쩌면... 당신이라면 그녀를 막을 수 있을지도 모르겠군요.","JPN":"もしかすると……あなたなら、彼女を止められるかもしれません。","ENG":"Perhaps... you might be the one who can stop her.","TWN":"或許……你真的能阻止她。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"당연히 막을 거야.","JPN":"当然止めるよ。","ENG":"Of course I'll stop her.","TWN":"我當然會阻止。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그걸 당신이 방해한다면, 당신 역시 꺾을 거고.","JPN":"あなたがその邪魔をするなら、あなたも倒す。","ENG":"And if you try to interfere, I'll defeat you as well.","TWN":"如果你要妨礙我，我也會擊潰你。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"...당신은 그럴 만큼 강합니다.","JPN":"……あなたはそれができるほど強い。","ENG":"...You're strong enough for that.","TWN":"……你確實有那個實力。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"하지만 아무리 강한 존재도, 결국 인간의 마음을 타고나면 중요한 순간에 큰 실수를 범하게 되죠.","JPN":"ですがいくら強い存在でも、人間の心を持っている以上は大事な瞬間に大きな間違いを犯すものです。","ENG":"But no matter how strong someone is, as long as they possess a human heart, they will make a grave mistake at a crucial moment.","TWN":"但無論是多強的存在，人類的心最終總會在關鍵時刻犯下重大錯誤。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"늑대! 그자의 말을 듣지 마셔요!","JPN":"オオカミ！　その者の言葉に耳を傾けてはなりません！","ENG":"Wolf! Do not listen to him!","TWN":"狼！不要聽他的！"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"더는 다른 사람들이 당신의 혀에 놀아나게 두지 않을 겁니다!","JPN":"もう二度と、人々があなたの言葉に翻弄されるままにしてはおかない！","ENG":"I'll no longer allow anyone else to be misled by your words!","TWN":"我不會再讓其他人被你玩弄於股掌之間！"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"여긴...?","JPN":"ここは……？","ENG":"Where is this...?","TWN":"這裡是……？"},"stage":{"bg":"MIND","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"레아 님...? 늑대...? 다들 어디로...","JPN":"レア様……？　オオカミ……？　皆さん、どこに……","ENG":"Ms. Leah...? Wolf...? Where did everyone go...?","TWN":"蕾亞……？狼……？大家都去哪了……"},"stage":{"bg":"MIND","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"낙원은 이면에 수많은 세계를 품고 있단다.","JPN":"楽園は裏に多くの世界を秘めているんだ。","ENG":"The Promised Land contains countless worlds within its depths.","TWN":"樂園在背後容納著無數世界。"},"stage":{"bg":"MIND","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"이 공간 역시 낙원이 삼킨 멸망한 세계 중 하나. 너희들 모두를 이런 곳에 보내두었다.","JPN":"この空間も楽園に呑み込まれ、滅びた世界の一つ。お前たち全員をこういう世界に送っておいたよ。","ENG":"This space as well is one of the ruined worlds that the Promised Land has swallowed. I sent all of you here.","TWN":"這個空間也是被樂園吞噬的毀滅世界之一，我把你們都送到這裡。"},"stage":{"bg":"MIND","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"...늑대 하나만을 제외하고 말이지.","JPN":"……オオカミだけは除いてね。","ENG":"...All except the Wolf.","TWN":"……除了狼之外。"},"stage":{"bg":"MIND","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"...아버지.","JPN":"……お父様。","ENG":"...Father.","TWN":"……父親。"},"stage":{"bg":"MIND","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"어찌하여 타기리온을 돕는 것입니까! 다른 세계를 멸망시켜가면서까지...!","JPN":"どうしてタギリオンを手伝うのですか！　他の世界を滅ぼしてまで……！","ENG":"Why are you helping Thagirion?! Even if it means destroying other worlds...!","TWN":"為什麼要幫助塔基里翁！甚至犧牲其他世界……！"},"stage":{"bg":"MIND","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"알고 있잖니. 완전한 낙원을 실현하기 위해서다.","JPN":"分かっているだろう。完全な楽園を実現するためだよ。","ENG":"You already know. It is to realize the perfect Promised Land.","TWN":"你不也知道嗎？為了實現完全的樂園。"},"stage":{"bg":"MIND","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_HATE"}}}},{"id":"L27_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"그리고 너희를 이곳에 격리하는 건, 이건 늑대를 위한 일이기도 하단다.","JPN":"そしてお前たちをここに隔離するのは、オオカミのためでもある。","ENG":"And isolating you here is also for the Wolf's sake.","TWN":"將你們隔離在這裡，也是為了狼。"},"stage":{"bg":"MIND","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_HATE"}}}},{"id":"L28_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"그런 터무니없는 궤변은 믿지 않을 것이옵니다!","JPN":"そんなデタラメな詭弁など信じません！","ENG":"I won't believe such absurd sophistry!","TWN":"我不會相信這種荒謬的歪理！"},"stage":{"bg":"MIND","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L30_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"마왕 타기리온이 가진 권능은, 인간의 가장 나약한 부분을 노리는 것에 타고나 있다.","JPN":"魔王タギリオンの権能は、人間の最も弱いところに付込むようにできているんだ。","ENG":"The power of the Demon Lord Thagirion is born to target the weakest parts of the human heart.","TWN":"魔王塔基里翁的能力，正是專門攻擊人類最脆弱的部分。"},"stage":{"bg":"MIND","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"가장 강한 적을 대적한다면, 그 곁을 지키는 다른 동료를 먼저 노려 집중을 방해하려 들겠지.","JPN":"最も強い敵が相手なら、そのそばにいる仲間を先に狙い、集中を乱すだろう。","ENG":"When facing the strongest enemy, she would first target the companions by their side to disrupt their focus.","TWN":"若面對強敵，她會先攻擊守在身旁的其他夥伴，分散其注意力。"},"stage":{"bg":"MIND","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"타기리온의 실이 너와 다른 동료들을 인형처럼 부리며, 늑대를 공격하기 시작한다면... 과연 늑대가 망설임 없이 너희를 벨 수 있을까?","JPN":"タギリオンの糸がお前とその仲間を操り人形にしてオオカミを攻撃し始めたら……オオカミは迷わず君たちを斬れると思うかい？","ENG":"If Thagirion's threads were to manipulate you and the others like puppets and make you attack the Wolf... would the Wolf truly be able to cut you down without hesitation?","TWN":"若塔基里翁的絲線像人偶一樣操控你和其他夥伴，轉而開始攻擊狼……狼能毫不猶豫地斬下你們嗎？"},"stage":{"bg":"MIND","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그럴싸한 핑계군요. 하지만 그게 늑대를 돕지 않을 이유는 못 됩니다.","JPN":"それっぽい口実ですね。ですが、それがオオカミと一緒に戦わない理由にはなりえません。","ENG":"That's a convincing excuse. But it still doesn't justify not helping the Wolf.","TWN":"說得很好聽。但這不能成為不幫助狼的理由。"},"stage":{"bg":"MIND","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"세상은 한 사람만의 힘으론 구할 수 없으니까요.","JPN":"世界は一人の力だけでは救えませんので。","ENG":"No one can save the world alone.","TWN":"光憑一己之力不能拯救世界。"},"stage":{"bg":"MIND","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"...참으로 인간다운 발상이군요. 하지만 나유빈, 당신도 그 <color=#ffd34c>함께</color>라는 가치 때문에 얼마나 많은 세계가 무너져 내렸는지 잘 알고 있지 않습니까?","JPN":"……実に人間らしい発想です。ですが、イチノセ・カオル。あなたもその<color=#ffd34c>一緒</color>という価値観のせいで崩壊した世界がどれだけ多いか、知っているはずです。","ENG":"...Such a very human way of thinking. But Na Yubin, you also know very well how many worlds have collapsed because of the value of <color=#ffd34c>together</color>, don't you?","TWN":"……思維還真像人類。不過羅瑜斌你應該很清楚，有多少世界會因為和你<color=#ffd34c>一起</color>為這個價值而毀滅？"},"stage":{"bg":"MIND","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"연대라는 것이, 결국 타기리온의 실에 얽혀 늑대의 가슴을 찌르게 되는 순간에도... 당신은 그 실패할 수밖에 없는 대적자의 운명을 <color=#ffd34c>최선</color>이라는 변명으로 포장할 수 있을까요?","JPN":"連帯というものが結局はタギリオンの糸にもつれ、オオカミの胸を貫く瞬間になっても……あなたは、失敗するしかない敵対者の運命を、<color=#ffd34c>最善</color>と言えますか？","ENG":"Even at the moment when your so-called solidarity becomes entangled in Thagirion's threads and pierces the Wolf's heart... would you still be able to sugarcoat the Antagonist's doomed fate with the excuse of it being <color=#ffd34c>the best choice</color>?","TWN":"即使連結最終讓你被塔基里翁的絲線纏住、刺向狼心臟的瞬間……你還能用<color=#ffd34c>最好</color>這種藉口來合理化那註定失敗的選擇嗎？"},"stage":{"bg":"MIND","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"당신들이 늑대 옆을 지키는 것은 도움도, 연대도 아닙니다. 그저 혼자가 아니면 해낼 수 없기에 자신의 목적을 이루기 위해 늑대의 칼날을 이용하겠다는 욕심일 뿐이지요.","JPN":"あなたたちがオオカミのそばにいることは助けにも連帯にもなりません。一人じゃないと成し遂げられないから、己の目的を達成するためにオオカミの刃を利用したいという欲に過ぎない。","ENG":"Standing beside the Wolf is neither help nor solidarity. It is nothing more than the desire to use the Wolf's blade to achieve your own goals because you cannot accomplish them alone.","TWN":"你們所謂的守在狼的身旁既不是協助，也不是連結。那不過是因為如果不是獨自一人就無法達成，為了實現自己的目的，而利用狼利刃的貪念罷了。"},"stage":{"bg":"MIND","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"그런 당신들의 욕심은 늑대를 약하게 만들 뿐이란 사실을, 여러분은 외면해왔을 뿐인 거죠.","JPN":"そんな欲がオオカミを弱くしているという事実から、あなたたちは目を逸らしてきただけです。","ENG":"You have simply turned a blind eye to the fact that such desire only makes the Wolf weaker.","TWN":"你們一直在忽視你們這種慾望，只會讓狼變得更軟弱的事實。"},"stage":{"bg":"MIND","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"당신께서 무슨 궤변을 늘어놓으시건, 저의 뜻을 굽힐 생각은 없사옵니다.","JPN":"お父様がどんな詭弁を並べようと、わたくしが挫けることはございません。","ENG":"No matter what kind of sophistry you try to justify it with, I have no intention of bending my will.","TWN":"不論你怎麼說，我都不會改變心意。"},"stage":{"bg":"MIND","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"늑대가 쓰러졌을 때, 누군가는 그녀가 일어설 시간을 벌어주어야 하니까요.","JPN":"オオカミが倒れた時、誰かは彼女が立ち上がる時間を稼ぐ必要がありますから。","ENG":"When the Wolf falls, someone must buy her the time she needs to rise again.","TWN":"當狼倒下時，總要有人為她爭取時間。"},"stage":{"bg":"MIND","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"그렇게 생각한다면, 여기서 날 쓰러트려 보아라.","JPN":"そう思うなら、ここで僕を倒してみなさい。","ENG":"If that is what you believe, then defeat me here.","TWN":"既然如此，就在這裡打倒我吧。"},"stage":{"bg":"MIND","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"타기리온의 농간에 휘둘리지 않을 만큼, 너의 각오에 그만한 결단력이 있는지 증명해보거라.","JPN":"タギリオンに利用されないくらい、お前の覚悟にそれだけの力があるのか証明してみせなさい。","ENG":"Prove that your resolve is strong enough not to be used by Thagirion.","TWN":"證明你的覺悟是否足以對抗塔基里翁，不被她利用。"},"stage":{"bg":"MIND","bgm":"THEMA_SECURITY_AGENT_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"무슨 일이 벌어진 거지?","JPN":"何が起きたんだ？","ENG":"What just happened?","TWN":"發生什麼事了？"},"stage":{"bg":"ANAPILIS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"다들... 어디로 사라진 거야?","JPN":"みんな……どこに消えたの？","ENG":"Where did everyone... disappear to?","TWN":"大家……都去哪了？"},"stage":{"bg":"ANAPILIS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"혼자 남겨진 기분은 어떤가요, 늑대?","JPN":"一人にされた感想はどうですか？　オオカミ。","ENG":"How does it feel to be left alone, Wolf?","TWN":"只剩下自己的感覺如何，狼？"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"당신이 믿을 수 있는 건, 이제 당신 자신 밖에 없어요.","JPN":"あなたが信じられるのは、もうあなた自身だけです。","ENG":"Now the only one you can rely on is yourself.","TWN":"你現在唯一能相信的，只有你自己。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"나 하나 뿐이라고?","JPN":"私一人だって？","ENG":"Only myself?","TWN":"只剩下我？"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"틀려. 애초에 모두의 도움이 있었기에 여기까지 올 수 있었던 거니까.","JPN":"違うよ。そもそもみんなの助けがあったからここまで来られたんだ。","ENG":"You're wrong. I was only able to come this far because of everyone's help.","TWN":"你錯了。正因為有大家的幫助，我才能走到這裡。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"이 자리에 혼자 있다 해도, 내가 그들 모두의 희망을 짊어지고 있단 사실은 변하지 않아.","JPN":"今ここに一人だとしても、私がみんなの希望を背負ってるという事実は変わらない。","ENG":"Even if I'm standing here alone now, it doesn't change the fact that I carry all of their hopes with me.","TWN":"即使現在只剩我一人，我仍背負著所有人的希望。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"고리타분한 말이군요.","JPN":"陳腐なセリフですね。","ENG":"Such an old-fashioned thing to say.","TWN":"真是老套的說法。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"하지만 한편으론 기대가 되네요. 당신이 짊어진 희망이란 게, 과연 저한테도 와닿을 수 있을지.","JPN":"ですが、同時に楽しみです。あなたが背負った希望とやらが果たして私に届くでしょうか。","ENG":"But at the same time, I'm looking forward to it. I wonder whether the hope you carry can reach me as well.","TWN":"但我倒是有點期待。你背負的希望，是否真的能觸動我。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"물론이지.","JPN":"もちろんだよ。","ENG":"Of course it will.","TWN":"當然可以。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"이번에야말로, 닿아주마.","JPN":"今度こそ、届けてみせる。","ENG":"This time for sure... it will reach you.","TWN":"這次一定會觸動你。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};